return [
  {
    json: {
      transcript_source_url: 'https://www.youtube.com/watch?v=dQw4w9WgXcQ',
      source_name: 'Video Transcript API smoke',
      source_type: 'transcript',
      media_type: 'video',
      use_speaker_recognition: false,
      published_at: new Date().toISOString(),
      obsidian_inbox_dir: '00_Inbox/AI_Information_Processor'
    }
  }
];

const sourceUrl = String($json.transcript_source_url || $json.url || '').trim();
if (!sourceUrl) {
  throw new Error('transcript_source_url is required for 04_video_transcript_ingest');
}

const baseUrl = String($env.VIDEO_TRANSCRIPT_BASE_URL || '').trim().replace(/\/+$/, '');
const apiKey = String($env.VIDEO_TRANSCRIPT_API_KEY || '').trim();
if (!baseUrl) {
  throw new Error('VIDEO_TRANSCRIPT_BASE_URL is required for 04_video_transcript_ingest');
}
if (!apiKey) {
  throw new Error('VIDEO_TRANSCRIPT_API_KEY is required for 04_video_transcript_ingest');
}

const metadataOverride = {};
for (const [sourceKey, targetKey] of [
  ['title', 'title'],
  ['author', 'author'],
  ['description', 'description']
]) {
  const value = String($json[sourceKey] || '').trim();
  if (value) {
    metadataOverride[targetKey] = value;
  }
}

const requestBody = {
  url: sourceUrl,
  use_speaker_recognition: Boolean($json.use_speaker_recognition),
};

const downloadUrl = String($json.download_url || '').trim();
if (downloadUrl) {
  requestBody.download_url = downloadUrl;
}

const wechatWebhook = String($json.wechat_webhook || '').trim();
if (wechatWebhook) {
  requestBody.wechat_webhook = wechatWebhook;
}

if (Object.keys(metadataOverride).length) {
  requestBody.metadata_override = metadataOverride;
}

return {
  json: {
    ...$json,
    transcript_source_url: sourceUrl,
    transcript_api: {
      base_url: baseUrl,
      api_key: apiKey,
      submit_url: `${baseUrl}/api/transcribe`,
      request_body: requestBody,
      poll_interval_ms: Math.max(1000, Number($json.poll_interval_ms || 3000)),
      max_polls: Math.max(1, Number($json.max_polls || 40))
    }
  }
};

const requestItem = $('Build Transcript API Request').item.json || {};
const submitResponse = $json || {};
const transcriptApi = requestItem.transcript_api || {};
const baseUrl = String(transcriptApi.base_url || '').replace(/\/+$/, '');
const apiKey = String(transcriptApi.api_key || '').trim();
const taskId = String(submitResponse?.data?.task_id || '').trim();
const viewToken = String(submitResponse?.data?.view_token || '').trim();

if (!baseUrl || !apiKey) {
  throw new Error('Transcript API connection info is missing after submission');
}
if (!taskId || !viewToken) {
  throw new Error(`Transcript API submit response missing task_id/view_token: ${JSON.stringify(submitResponse)}`);
}

return {
  json: {
    ...requestItem,
    submit_response: submitResponse,
    upstream_task_id: taskId,
    upstream_view_token: viewToken,
    poll_attempt: 0,
    poll_state: 'pending',
    task_status_url: `${baseUrl}/api/task/${encodeURIComponent(taskId)}`,
    transcript_exports: {
      calibrated: `${baseUrl}/view/${viewToken}?raw=calibrated`,
      transcript: `${baseUrl}/view/${viewToken}?raw=transcript`,
      summary: `${baseUrl}/view/${viewToken}?raw=summary`
    }
  }
};

if (!String($json.task_status_url || '').trim()) {
  throw new Error('task_status_url is required before polling Transcript API task status');
}

return {
  json: {
    ...$json
  }
};

const context = $('Prepare Transcript Task Status Request').item.json || {};
const taskStatus = $json || {};
const maxPolls = Math.max(1, Number(context.transcript_api?.max_polls || 40));
const nextAttempt = Number(context.poll_attempt || 0) + 1;
const responseCode = Number(taskStatus.code || 0);

if (!Number.isFinite(responseCode)) {
  throw new Error(`Transcript API task status returned a non-numeric code: ${JSON.stringify(taskStatus)}`);
}

if (responseCode === 202) {
  if (nextAttempt >= maxPolls) {
    throw new Error(`Transcript API task ${context.upstream_task_id || 'unknown'} did not finish within ${maxPolls} polls`);
  }

  return {
    json: {
      ...context,
      poll_attempt: nextAttempt,
      poll_state: 'pending',
      transcript_status: String(taskStatus.message || '').trim()
    }
  };
}

if (responseCode >= 500) {
  throw new Error(`Transcript API task ${context.upstream_task_id || 'unknown'} failed: ${taskStatus.message || 'unknown error'}`);
}

const firstNonEmptyString = (...values) => {
  for (const value of values) {
    const normalized = String(value || '').trim();
    if (normalized) {
      return normalized;
    }
  }
  return '';
};

const normalizeMultiline = (value = '') => String(value || '')
  .replace(/\r\n/g, '\n')
  .replace(/\u0000/g, '')
  .replace(/[ \t]+\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const normalizeSingleLine = (value = '') => normalizeMultiline(value)
  .replace(/\s+/g, ' ')
  .trim();

const toOptionalNumber = (...values) => {
  for (const value of values) {
    const numericValue = Number(value);
    if (Number.isFinite(numericValue) && numericValue >= 0) {
      return Number(numericValue.toFixed(3));
    }
  }
  return null;
};

const asObject = (value) => value && typeof value === 'object' && !Array.isArray(value) ? value : null;

const readDurationFromSegments = (segments) => {
  if (!Array.isArray(segments)) {
    return null;
  }
  let maxEnd = null;
  for (const segment of segments) {
    if (!segment || typeof segment !== 'object') {
      continue;
    }
    const endValue = toOptionalNumber(segment.end, segment.end_time, segment.stop, segment.stop_time);
    if (endValue !== null) {
      maxEnd = maxEnd === null ? endValue : Math.max(maxEnd, endValue);
    }
  }
  return maxEnd === null ? null : Number(maxEnd.toFixed(3));
};

const deriveDurationSeconds = (payload) => {
  const root = asObject(payload);
  if (!root) {
    return null;
  }

  const directDuration = toOptionalNumber(root.duration_seconds, root.duration, root.audio_duration, root.video_duration);
  if (directDuration !== null) {
    return directDuration;
  }

  const transcriptionPayload = root.transcription_data;
  const candidates = [
    root.segments,
    root.sentences,
    root.result,
    Array.isArray(transcriptionPayload) ? transcriptionPayload : null,
    asObject(transcriptionPayload)?.segments,
    asObject(transcriptionPayload)?.sentences,
    asObject(transcriptionPayload)?.result
  ];

  for (const candidate of candidates) {
    const derived = readDurationFromSegments(candidate);
    if (derived !== null) {
      return derived;
    }
  }

  return null;
};

const detectLanguage = (text, fallback = '') => {
  const normalizedFallback = String(fallback || '').trim().toLowerCase();
  if (normalizedFallback) {
    return normalizedFallback;
  }

  const cjkCount = (String(text || '').match(/[\u4e00-\u9fff]/g) || []).length;
  const latinCount = (String(text || '').match(/[A-Za-z]/g) || []).length;
  if (cjkCount >= 20) {
    return 'zh';
  }
  if (latinCount >= 20) {
    return 'en';
  }
  return 'unknown';
};

const normalizeSpeaker = (value) => {
  const normalized = normalizeSingleLine(value);
  if (!normalized) {
    return '';
  }
  if (/^speaker\d+$/i.test(normalized)) {
    return normalized.replace(/^speaker/i, 'Speaker');
  }
  if (/^\d+$/.test(normalized)) {
    return `Speaker${normalized}`;
  }
  return normalized;
};

const formatTimestamp = (value) => {
  const numericValue = Number(value);
  if (!Number.isFinite(numericValue) || numericValue < 0) {
    return '';
  }

  const wholeSeconds = Math.floor(numericValue);
  const hours = String(Math.floor(wholeSeconds / 3600)).padStart(2, '0');
  const minutes = String(Math.floor((wholeSeconds % 3600) / 60)).padStart(2, '0');
  const seconds = String(wholeSeconds % 60).padStart(2, '0');
  const milliseconds = Math.round((numericValue - wholeSeconds) * 1000);

  return milliseconds > 0
    ? `${hours}:${minutes}:${seconds}.${String(milliseconds).padStart(3, '0')}`
    : `${hours}:${minutes}:${seconds}`;
};

const buildTopicHint = (text = '') => {
  const normalized = normalizeMultiline(text).replace(/\n+/g, ' ');
  if (!normalized) {
    return '';
  }

  const withoutSpeaker = normalized.replace(/^[^:：]{1,30}[:：]\s*/, '');
  const firstClause = withoutSpeaker.match(/^.{1,24}?(?=[。！？!?；;，,:]|$)/)?.[0] || withoutSpeaker.slice(0, 24);
  return firstClause.trim();
};

const splitTextByBoundary = (text, maxChars) => {
  const normalized = normalizeMultiline(text);
  if (!normalized) {
    return [];
  }
  if (normalized.length <= maxChars) {
    return [normalized];
  }

  const sentenceParts = normalized
    .split(/(?<=[。！？!?；;])/)
    .map((part) => normalizeMultiline(part))
    .filter(Boolean);
  const inputParts = sentenceParts.length ? sentenceParts : [normalized];
  const pieces = [];
  let buffer = '';

  const flushBuffer = () => {
    const normalizedBuffer = normalizeMultiline(buffer);
    if (normalizedBuffer) {
      pieces.push(normalizedBuffer);
    }
    buffer = '';
  };

  const appendPart = (part) => {
    if (!part) {
      return;
    }

    if (part.length > maxChars) {
      flushBuffer();
      for (let cursor = 0; cursor < part.length; cursor += maxChars) {
        const slice = normalizeMultiline(part.slice(cursor, cursor + maxChars));
        if (slice) {
          pieces.push(slice);
        }
      }
      return;
    }

    const candidate = buffer ? `${buffer}${part}` : part;
    if (buffer && candidate.length > maxChars) {
      flushBuffer();
      buffer = part;
      return;
    }

    buffer = candidate;
  };

  for (const part of inputParts) {
    appendPart(part);
  }

  flushBuffer();
  return pieces;
};

const splitStructuredSegment = (segment, maxChars) => {
  if (!segment || !segment.text) {
    return [];
  }

  const parts = splitTextByBoundary(segment.text, maxChars);
  if (parts.length <= 1) {
    return [segment];
  }

  const hasTimeRange = Number.isFinite(segment.start_time) && Number.isFinite(segment.end_time) && segment.end_time > segment.start_time;
  const totalLength = parts.reduce((sum, part) => sum + part.length, 0) || segment.text.length || 1;
  let cursor = 0;

  return parts.map((part) => {
    let partStart = segment.start_time;
    let partEnd = segment.end_time;

    if (hasTimeRange) {
      const startRatio = cursor / totalLength;
      const endRatio = (cursor + part.length) / totalLength;
      partStart = Number((segment.start_time + ((segment.end_time - segment.start_time) * startRatio)).toFixed(3));
      partEnd = Number((segment.start_time + ((segment.end_time - segment.start_time) * endRatio)).toFixed(3));
    }

    cursor += part.length;

    return {
      start_time: partStart,
      end_time: partEnd,
      speaker: segment.speaker,
      text: part
    };
  });
};

const extractStructuredSegments = (payload, transcriptionPayload) => {
  const candidates = [];
  if (Array.isArray(transcriptionPayload)) {
    candidates.push(transcriptionPayload);
  }
  if (transcriptionPayload && typeof transcriptionPayload === 'object') {
    candidates.push(transcriptionPayload.segments, transcriptionPayload.sentences, transcriptionPayload.result);
  }
  if (payload && typeof payload === 'object') {
    candidates.push(payload.segments, payload.sentences, payload.result);
  }

  for (const candidate of candidates) {
    if (Array.isArray(candidate) && candidate.length) {
      return candidate;
    }
  }

  return [];
};

const normalizeStructuredSegment = (segment) => {
  if (!segment || typeof segment !== 'object') {
    return null;
  }

  const text = normalizeMultiline(segment.text || segment.content || segment.value || segment.sentence || '');
  if (!text) {
    return null;
  }

  return {
    start_time: toOptionalNumber(segment.start_time, segment.start, segment.begin_time, segment.begin, segment.offset_start, segment.from),
    end_time: toOptionalNumber(segment.end_time, segment.end, segment.stop_time, segment.stop, segment.offset_end, segment.to),
    speaker: normalizeSpeaker(segment.speaker || segment.speaker_name || segment.speaker_id || segment.spk_id || segment.spk || ''),
    text
  };
};

const buildTranscriptChunks = (text, payload, transcriptionPayload, profile) => {
  const structuredSegments = extractStructuredSegments(payload, transcriptionPayload)
    .map((segment) => normalizeStructuredSegment(segment))
    .filter(Boolean)
    .flatMap((segment) => splitStructuredSegment(segment, profile.maxChars));

  if (structuredSegments.length) {
    const merged = [];

    for (const segment of structuredSegments) {
      const previous = merged.length ? merged[merged.length - 1] : null;
      const sameSpeaker = previous && (previous.speaker || '') === (segment.speaker || '');
      const combinedLength = previous ? previous.text.length + 1 + segment.text.length : 0;

      if (previous && sameSpeaker && combinedLength <= profile.maxChars) {
        previous.text = `${previous.text}\n${segment.text}`.trim();
        previous.end_time = segment.end_time ?? previous.end_time;
        continue;
      }

      merged.push({ ...segment });
    }

    return {
      strategy: 'structured',
      chunks: merged.map((segment) => ({
        ...segment,
        topic_hint: buildTopicHint(segment.text)
      }))
    };
  }

  const normalizedText = normalizeMultiline(text);
  if (!normalizedText) {
    return { strategy: 'fallback', chunks: [] };
  }

  const paragraphs = normalizedText.split(/\n{2,}/).map((paragraph) => normalizeMultiline(paragraph)).filter(Boolean);
  const paragraphSeeds = (paragraphs.length ? paragraphs : [normalizedText]).flatMap((paragraph) => {
    const speakerMatch = paragraph.match(/^([^\n:：]{1,30})[:：]\s*([\s\S]+)$/);
    const speaker = speakerMatch ? normalizeSpeaker(speakerMatch[1]) : '';
    const body = normalizeMultiline(speakerMatch ? speakerMatch[2] : paragraph);

    return splitTextByBoundary(body, profile.maxChars).map((part) => ({
      speaker,
      text: part,
      topic_hint: buildTopicHint(part)
    }));
  });

  const merged = [];
  for (const segment of paragraphSeeds) {
    const previous = merged.length ? merged[merged.length - 1] : null;
    const sameSpeaker = previous && (previous.speaker || '') === (segment.speaker || '');
    const combinedLength = previous ? previous.text.length + 1 + segment.text.length : 0;

    if (previous && sameSpeaker && combinedLength <= profile.maxChars && previous.text.length < profile.minChars) {
      previous.text = `${previous.text}\n${segment.text}`.trim();
      previous.topic_hint = buildTopicHint(previous.text);
      continue;
    }

    merged.push({ ...segment });
  }

  return { strategy: 'fallback', chunks: merged };
};

const taskData = taskStatus.data && typeof taskStatus.data === 'object' ? taskStatus.data : {};
const transcriptText = normalizeMultiline(taskData.transcript || '');
if (!transcriptText) {
  throw new Error(`Transcript API task ${context.upstream_task_id || 'unknown'} completed without transcript text`);
}

const transcriptionData = Array.isArray(taskData.transcription_data)
  ? taskData.transcription_data
  : asObject(taskData.transcription_data);
const transcriptionType = firstNonEmptyString(
  taskData.transcription_type,
  Array.isArray(transcriptionData) ? '' : transcriptionData?.transcript_type,
  context.transcription_type
);
const useSpeakerRecognition = Boolean(taskData.use_speaker_recognition ?? context.use_speaker_recognition);
const serviceSummary = firstNonEmptyString(
  taskData.summary,
  taskData.llm_summary,
  taskData.service_summary,
  taskData.summary_text
);
const chunkProfile = {
  minChars: 600,
  maxChars: String(context.media_type || '').trim().toLowerCase() === 'text' ? 1500 : 1200
};
const transcriptChunkResult = buildTranscriptChunks(transcriptText, taskData, transcriptionData, chunkProfile);
const transcriptChunks = transcriptChunkResult.chunks.map((chunk, index) => {
  const hasTimeRange = chunk.start_time != null || chunk.end_time != null;
  return {
    chunk_id: `${hasTimeRange ? 't' : 'c'}${String(index + 1).padStart(hasTimeRange ? 4 : 3, '0')}`,
    ...(chunk.start_time != null ? { start_time: formatTimestamp(chunk.start_time) } : {}),
    ...(chunk.end_time != null ? { end_time: formatTimestamp(chunk.end_time) } : {}),
    ...(chunk.speaker ? { speaker: chunk.speaker } : {}),
    text: chunk.text,
    ...(chunk.topic_hint ? { topic_hint: chunk.topic_hint } : {})
  };
});

const transcriptServiceMeta = {
  backend: 'VideoTranscriptAPI',
  asr_provider: transcriptionType === 'funasr' || useSpeakerRecognition
    ? 'FunASR'
    : transcriptionType === 'capswriter'
      ? 'CapsWriter'
      : 'CapsWriter',
  duration_seconds: deriveDurationSeconds(taskData),
  language: detectLanguage(transcriptText, taskData.language || context.language),
  transcript_quality: firstNonEmptyString(
    taskData.transcript_quality,
    taskData.quality,
    taskData.quality_label,
    context.transcript_quality
  ) || 'unknown',
  cache_hit: Boolean(
    taskData.cache_hit === true
    || taskData.from_cache === true
    || context.submit_response?.data?.cache_hit === true
  ),
  service_summary_present: Boolean(serviceSummary),
  chunk_count: transcriptChunks.length,
  chunking_strategy: transcriptChunkResult.strategy
};

const originalItem = {
  request: context.transcript_api?.request_body || {},
  submit_response: context.submit_response || {},
  task_status: taskStatus,
  transcript_exports: context.transcript_exports || {},
  transcript_service_meta: transcriptServiceMeta,
  transcript_chunking: {
    strategy: transcriptChunkResult.strategy,
    chunk_count: transcriptChunks.length
  }
};
if (serviceSummary) {
  originalItem.transcript_service_summary = serviceSummary;
}

return {
  json: {
    ...context,
    poll_attempt: nextAttempt,
    poll_state: 'completed',
    upstream_summary: serviceSummary || String(context.upstream_summary || '').trim(),
    canonical_url: String(context.canonical_url || context.transcript_source_url || '').trim(),
    original_id: String(context.original_id || `video-transcript:${context.upstream_view_token || 'unknown'}`).trim(),
    title: String(taskData.video_title || context.title || 'untitled transcript item').trim() || 'untitled transcript item',
    author: String(taskData.author || context.author || '').trim(),
    published_at: context.published_at || new Date().toISOString(),
    transcript_text: transcriptText,
    transcript_status: String(taskStatus.message || '').trim(),
    transcript_service_meta: transcriptServiceMeta,
    chunks: transcriptChunks,
    original_item: originalItem
  }
};

const delayMs = Math.max(1000, Number($json.transcript_api?.poll_interval_ms || 3000));
await new Promise((resolve) => setTimeout(resolve, delayMs));
return {
  json: {
    ...$json
  }
};

const normalizeMultiline = (value = '') => String(value || '')
  .replace(/\r\n/g, '\n')
  .replace(/\u0000/g, '')
  .replace(/[ \t]+\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const normalizeSingleLine = (value = '') => normalizeMultiline(value)
  .replace(/\s+/g, ' ')
  .trim();

const normalizeTimestamp = (value = '') => {
  const normalized = String(value || '').trim();
  if (!normalized) {
    return '';
  }

  const match = normalized.match(/^(\d{1,2}):(\d{2}):(\d{2})(?:\.(\d{1,3}))?$/);
  if (!match) {
    return '';
  }

  return `${match[1].padStart(2, '0')}:${match[2]}:${match[3]}${match[4] ? `.${match[4].padEnd(3, '0')}` : ''}`;
};

const normalizeChunks = (value) => {
  if (!Array.isArray(value)) {
    return [];
  }

  const normalized = [];
  for (const chunk of value) {
    if (!chunk || typeof chunk !== 'object') {
      continue;
    }

    const text = normalizeMultiline(chunk.text || chunk.content || '');
    if (!text) {
      continue;
    }

    const chunkId = normalizeSingleLine(chunk.chunk_id || chunk.chunkId || '');
    const startTime = normalizeTimestamp(chunk.start_time || chunk.startTime || '');
    const endTime = normalizeTimestamp(chunk.end_time || chunk.endTime || '');
    const speaker = normalizeSingleLine(chunk.speaker || chunk.speaker_name || '');
    const topicHint = normalizeSingleLine(chunk.topic_hint || chunk.topicHint || '');

    normalized.push({
      ...(chunkId ? { chunk_id: chunkId } : {}),
      ...(startTime ? { start_time: startTime } : {}),
      ...(endTime ? { end_time: endTime } : {}),
      ...(speaker ? { speaker } : {}),
      text,
      ...(topicHint ? { topic_hint: topicHint } : {})
    });
  }

  return normalized;
};

const transcriptText = normalizeMultiline($json.transcript_text || $json.calibrated_transcript || '');
if (!transcriptText) {
  throw new Error('Resolved transcript payload is missing transcript_text');
}

const obsidianInboxDir = String($json.obsidian_inbox_dir || $env.OBSIDIAN_INBOX_DIR || '00_Inbox/AI_Information_Processor').trim() || '00_Inbox/AI_Information_Processor';
const requestedTags = Array.isArray($json.extra_tags) ? $json.extra_tags : [];
const extraTags = [...new Set([
  'transcript',
  ...requestedTags.map((tag) => String(tag).trim())
].filter(Boolean))];
const normalizedChunks = normalizeChunks($json.chunks);
const transcriptServiceMeta = $json.transcript_service_meta && typeof $json.transcript_service_meta === 'object' && !Array.isArray($json.transcript_service_meta)
  ? { ...$json.transcript_service_meta }
  : {};
if (normalizedChunks.length) {
  transcriptServiceMeta.chunk_count = normalizedChunks.length;
}
const upstreamSummary = String($json.upstream_summary || '').trim();
const originalItem = $json.original_item && typeof $json.original_item === 'object' && !Array.isArray($json.original_item)
  ? { ...$json.original_item }
  : {};
if (Object.keys(transcriptServiceMeta).length) {
  originalItem.transcript_service_meta = transcriptServiceMeta;
}
if (upstreamSummary) {
  originalItem.upstream_summary = upstreamSummary;
}
const finalOriginalItem = Object.keys(originalItem).length ? originalItem : ($json.original_item ?? $json);

return {
  json: {
    source_type: String($json.source_type || 'transcript').trim() || 'transcript',
    source_name: String($json.source_name || 'video-transcript-api').trim() || 'video-transcript-api',
    canonical_url: String($json.canonical_url || $json.transcript_source_url || '').trim(),
    original_id: String($json.original_id || '').trim(),
    title: String($json.title || 'untitled').trim() || 'untitled',
    author: String($json.author || '').trim(),
    published_at: $json.published_at || new Date().toISOString(),
    media_type: String($json.media_type || 'video').trim() || 'video',
    raw_html: '',
    raw_text: transcriptText,
    ...(normalizedChunks.length ? { chunks: normalizedChunks } : {}),
    obsidian_inbox_dir: obsidianInboxDir,
    extra_tags: extraTags,
    upstream_task_id: String($json.upstream_task_id || '').trim(),
    upstream_view_token: String($json.upstream_view_token || '').trim(),
    upstream_summary: upstreamSummary,
    transcript_service_meta: transcriptServiceMeta,
    original_item: finalOriginalItem
  }
};
